mapper.select:
SELECT tll.login_log_seq, tu.user_id, tll.user_seq, tll.login_date_time, tll.access_ip, tll.user_agent, tu.user_name, tcd.cm_nm as access_nm FROM tb_login_log tll INNER JOIN tb_user tu ON tll.user_seq = tu.user_seq LEFT OUTER JOIN TB_COM_CD TCD ON tll.access_cd = tcd.cm_std_cd WHERE 1=1
AND tll.login_date_time BETWEEN TO_TIMESTAMP(#{startDate}::TEXT || ' 00:00:01', 'YYYY-MM-DD HH24:MI:SS')AND TO_TIMESTAMP(#{endDate}::TEXT || ' 23:59:59', 'YYYY-MM-DD HH24:MI:SS')
AND tu.user_id = #{userId}
AND tu.use_flag = #{useFlag}
ORDER BY tll.login_date_time DESC
